import React, { useState, useEffect } from 'react';
import { api } from '../services/api'; // Cambiado: Usamos tu servicio centralizado
import { useAuth } from '../context/AuthContext';
import { Package, MapPin, Clock, CheckCircle, Truck, AlertCircle, Loader2 } from 'lucide-react';

const MisPedidosCliente = () => {
  const [pedidos, setPedidos] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();

  useEffect(() => {
    const fetchPedidos = async () => {
      try {
        const clienteId = user?.id || user?._id;
        if (!clienteId) return;

        // Sincronizamos con la nube usando el nuevo api.js
        const data = await api.getPedidosCliente(clienteId);
        setPedidos(Array.isArray(data) ? data : []);
      } catch (error) {
        console.error("Error al obtener historial de pedidos de la nube:", error);
      } finally {
        setLoading(false);
      }
    };

    if (user) fetchPedidos();
  }, [user]);

  const getStatusIcon = (estado) => {
    switch (estado?.toLowerCase()) {
      case 'pendiente': 
      case 'proceso': return <Clock size={18} color="#e67e22" />;
      case 'camino': return <Truck size={18} color="#3182ce" />;
      case 'completado': return <CheckCircle size={18} color="#22c55e" />;
      default: return <AlertCircle size={18} color="#ef4444" />;
    }
  };

  if (loading) return (
    <div style={msgContainer}>
        <Loader2 size={40} className="spinner" color="#e67e22" />
        <p>Cargando tus pedidos desde la nube...</p>
    </div>
  );

  if (pedidos.length === 0) {
    return (
      <div style={msgContainer}>
        <Package size={48} color="#cbd5e1" />
        <h3 style={{ margin: '10px 0 0 0', color: '#1e293b' }}>Sin pedidos aún</h3>
        <p>Tus compras aparecerán aquí para que puedas retirarlas.</p>
      </div>
    );
  }

  return (
    <div style={container}>
      <h2 style={title}>Mis Pedidos</h2>
      <div style={listContainer}>
        {pedidos.map((pedido) => (
          <div key={pedido._id} style={orderCard}>
            <div style={orderHeader}>
              <div style={statusBadge}>
                {getStatusIcon(pedido.estado)}
                <span style={statusText}>{(pedido.estado || 'PENDIENTE').toUpperCase()}</span>
              </div>
              <span style={dateText}>
                {pedido.createdAt ? new Date(pedido.createdAt).toLocaleDateString() : 'Reciente'}
              </span>
            </div>

            <div style={bodyCard}>
              <div style={localInfo}>
                <h4 style={localName}>{pedido.local?.nombre || "Local de Ofertas"}</h4>
                <div style={addressRow}>
                  <MapPin size={14} color="#94a3b8" />
                  <span>{pedido.local?.direccion || "Retiro en sucursal"}</span>
                </div>
              </div>

              <div style={itemsList}>
                {pedido.items?.map((item, idx) => (
                  <div key={idx} style={itemRow}>
                    <span>{item.cantidad}x {item.productoNombre || 'Producto'}</span>
                    <span>${(item.precioUnitario || 0) * item.cantidad}</span>
                  </div>
                ))}
              </div>

              <div style={divider} />

              <div style={totalRow}>
                <span>Total pagado</span>
                <span style={totalPrice}>${pedido.total}</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const container = { padding: '20px', maxWidth: '600px', margin: '0 auto', fontFamily: 'sans-serif' };
const title = { color: '#1e293b', marginBottom: '20px', fontSize: '1.5rem', fontWeight: 'bold' };
const msgContainer = { display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '100px 20px', color: '#64748b', textAlign: 'center', gap: '15px' };
const listContainer = { display: 'flex', flexDirection: 'column', gap: '20px' };

const orderCard = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const orderHeader = { padding: '15px 20px', background: '#f8fafc', borderBottom: '1px solid #e2e8f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };

const statusBadge = { display: 'flex', alignItems: 'center', gap: '8px', background: 'white', padding: '6px 12px', borderRadius: '12px', border: '1px solid #e2e8f0' };
const statusText = { fontSize: '0.75rem', fontWeight: 'bold', color: '#1e293b' };
const dateText = { fontSize: '0.8rem', color: '#94a3b8' };

const bodyCard = { padding: '20px' }; 
const localInfo = { borderBottom: '1px solid #f1f5f9', paddingBottom: '12px', marginBottom: '12px' };
const localName = { margin: '0 0 5px 0', fontSize: '1.1rem', color: '#1e293b', fontWeight: 'bold' };
const addressRow = { display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.85rem', color: '#64748b' };

const itemsList = { display: 'flex', flexDirection: 'column', gap: '8px', marginBottom: '15px', marginTop: '10px' };
const itemRow = { display: 'flex', justifyContent: 'space-between', fontSize: '0.9rem', color: '#334155' };
const divider = { height: '1px', background: '#f1f5f9', margin: '15px 0' };

const totalRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', fontWeight: 'bold' };
const totalPrice = { fontSize: '1.2rem', color: '#e67e22', fontWeight: '900' };

export default MisPedidosCliente;
